Event Start
LoadWWPContext.Call(&Context) &FilPesCod = &Context.PesCod &EmpCod = &Context.EmpCod retornaAutorizacao.Call('WPDUPLICATASPAGAS', Status_SimNao.Sim, 1, &AutNiv)
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&IsMostrarObs.TooltipText = "Marcando esta opção, sera mostrado as observações da duplicata " &DDO_TitleSettingsIcons = GetWWPTitleSettingsIcons() &CreFrpPgtoCod.Visible = False &IsSintetico.TooltipText = "Marque esta opção para o relatório sair no modo sintético (Resumido)" &AreCod.Visible = False &CreCbrCod.Visible = False &CidCod.Visible = False &UfeCod.Visible = False Do 'LoadComboUfeCod' Do 'LoadComboCidCod' Do 'LoadComboCreCbrCod' Do 'LoadComboAreCod' Do 'LoadComboCreFrpPgtoCod'
Do 'AttributesSecurityCode'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Do 'montaFilialFaturamento' &isReceber = 'R'
Do 'Cliente' Do 'Vendedor' &CrePagDta = serverdate() &CrePagDta_to = &CrePagDta &CrepagDta = &CrePagDta.AddDays(-30)
EndEvent
Event Combo_CreFrpPgtoCod.OnOptionClicked
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&CreFrpPgtoCod.FromString(Combo_CreFrpPgtoCod.SelectedValue_get)
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
// msg(&CreFrpPgtoCod.ToString())
EndEvent
Event Combo_AreCod.OnOptionClicked
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&AreCod.FromString(Combo_AreCod.SelectedValue_get)
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Combo_CreCbrCod.OnOptionClicked
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&CreCbrCod.FromString(Combo_CreCbrCod.SelectedValue_get)
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Combo_CidCod.OnOptionClicked
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&CidCod.FromString(Combo_CidCod.SelectedValue_get)
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Combo_UfeCod.OnOptionClicked
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&UfeCod = Combo_UfeCod.SelectedValue_get
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
do 'LoadComboCidCod'
EndEvent
Sub 'AttributesSecurityCode'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If Not (&IsSintetico = False) &IsMostrarObs.Visible = False IsMostrarObs_Cell.Class = !'Invisible' Else &IsMostrarObs.Visible = True IsMostrarObs_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf If Not (&IsSintetico <> true) &IsDetalhaPedido.Visible = False IsDetalhaPedido_Cell.Class = !'Invisible' Else &IsDetalhaPedido.Visible = True IsDetalhaPedido_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadComboCreFrpPgtoCod'
RetornaFormasPagamento.Call(&Context.EmpCod, 'R', '', &Context.PesCod, &Context.TipoPerfil, &padFrpPgtoCod, &sdtFormasPagamento) &CreFrpPgtoCod_Data.Clear() &CreFrpPgtoCod = 0 For &sdtFormasPagamentoItem in &sdtFormasPagamento &Combo_DataItem = new() &Combo_DataItem.ID = &sdtFormasPagamentoItem.FrpPgtoCod.ToString() &Combo_DataItem.Title = &sdtFormasPagamentoItem.FrpPgtoNom &CreFrpPgtoCod_data.Add(&Combo_DataItem) EndFor
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
//&CreFrpPgtoCod initial value has to be loaded manually at the beginning of this Subrutine //&CreFrpPgtoCod_Data has to be loaded manually at the beginning of this Subrutine &CreFrpPgtoCod_Data.Sort(!'Title') Combo_CreFrpPgtoCod.SelectedValue_set = iif(&CreFrpPgtoCod.IsEmpty(), '', &CreFrpPgtoCod.ToString().Trim())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadComboAreCod'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
//&AreCod initial value has to be loaded manually at the beginning of this Subrutine For Each Order AreCodNom Where EmpCod = &Context.EmpCod &Combo_DataItem = new() &Combo_DataItem.ID = AreCod.ToString().Trim() &Combo_DataItem.Title = AreCodNom &AreCod_Data.Add(&Combo_DataItem) EndFor Combo_AreCod.SelectedValue_set = iif(&AreCod.IsEmpty(), '', &AreCod.ToString().Trim())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadComboCreCbrCod'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
//&CreCbrCod initial value has to be loaded manually at the beginning of this Subrutine For Each Where EmpCod = &Context.EmpCod and CbrSts = Status_AtivoInativo.ATIVO &Combo_DataItem = new() &Combo_DataItem.ID = CbrCod.ToString().Trim() &Combo_DataItem.Title = CbrCodNom &CreCbrCod_Data.Add(&Combo_DataItem) EndFor Combo_CreCbrCod.SelectedValue_set = iif(&CreCbrCod.IsEmpty(), '', &CreCbrCod.ToString().Trim())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadComboCidCod'
&CidCod_Data.Clear() Combo_CidCod.SelectedValue_set = '' &CidCod = 0
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
//&CidCod initial value has to be loaded manually at the beginning of this Subrutine For Each Order CidNomUfe Where EmpCod = &Context.EmpCod where &UfeCod = UfeCod when not &UfeCod.IsEmpty() &Combo_DataItem = new() &Combo_DataItem.ID = CidCod.ToString().Trim() &Combo_DataItem.Title = CidNomUfe &CidCod_Data.Add(&Combo_DataItem) EndFor Combo_CidCod.SelectedValue_set = iif(&CidCod.IsEmpty(), '', &CidCod.ToString().Trim())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadComboUfeCod'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
//&UfeCod initial value has to be loaded manually at the beginning of this Subrutine For Each Order UfeCodNom Where EmpCod = &Context.EmpCod &Combo_DataItem = new() &Combo_DataItem.ID = UfeCod &Combo_DataItem.Title = UfeCodNom &UfeCod_Data.Add(&Combo_DataItem) EndFor Combo_UfeCod.SelectedValue_set = &UfeCod
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Event &PesCod.IsValid
Do 'Vendedor'
EndEvent
Event &IsSintetico.Click
Do 'AttributesSecurityCode' &IsMostrarObs = false
if &IsSintetico = true &Ordenar.RemoveItem('D') else &Ordenar.AddItem('D', 'Data pagamento') endif
EndEvent
Event &CreCliCod.IsValid
Do 'Cliente'
EndEvent
Event Enter
do case case not &CrePagDta_To.IsEmpty() and &CrePagDta > &CrePagDta_To Msg(DVMessageBasicNotification('', 'Data de pagamento inicial não pode ser maior que final', DVMessageType.error, '', DVMessageBoolean.True)) otherwise RCOOpenWindow1.LinkOpen = RELJAS151.Link(&Context.EmpCod,&Context.FilCod,&Ordenar,&AreCod,&CidCod,&UfeCod,&CreFrpPgtoCod,&CreCliCod,&CrePagDta,&CrePagDta_To,&PesCod,&CreCbrCod,&isReceber,&IsSintetico,&IsMostrarObs,&IsPedido,&IsDetalhaPedido,&CreFilPgt) RCOOpenWindow1.OpenWindow(True, 500, 500, True, 0, 0, False) endcase
EndEvent
Sub 'montaFilialFaturamento'
&CreFilPgt.Clear() &CreFilPgt.AddItem(0, '0 - TODAS FILIAIS') tbFilialFaturamento.Visible = 0
For &Filials in &Context.Filials &CreFilPgt.AddItem(&Filials.FilCodVin, gxGetMLi(&Filials.FilRazVin, 1, 25)) EndFor
if &Context.Filials.Count > 1 tbFilialFaturamento.Visible = 1 Endif
EndSub
Sub 'Vendedor'
If not &PesCod.IsEmpty() For Each Order EmpCod,PesCod Where EmpCod = &EmpCod Where PesCod = &PesCod Where PesIsVen = True
&PesRaz = PesRaz Exit When none msg('ATENÇÃO! Vendedor não encontrado ou pessoa não é vendedor. Verifique!') &PesRaz = 'Vendedor não encontrado.' &PesCod.SetFocus() EndFor Else &PesRaz = 'Todos os Vendedores' EndIf
EndSub
Sub 'Cliente'
If &CreCliCod <> 0 For Each Order EmpCod,PesCod Where EmpCod = &EmpCod Where PesCod = &CreCliCod &CreCliRaz = substr(PesRaz,1,30) Exit When none Msg(DVMessageBasicNotification('', 'ATENÇÃO! Cliente não encontrado ou pessoa não é cliente. Verifique!', DVMessageType.error, '', DVMessageBoolean.True)) &CreCliRaz = 'Cliente não encontrado.' &CreCliCod.SetFocus() EndFor Else &CreCliRaz = 'Todos os clientes' EndIf
EndSub
